// Native straddle desk and volatility skew renderers
 async function refreshStraddleChain(forceExpiryKey) {
 const requestedExpiry = forceExpiryKey || state.straddleChain?.expiryKey || state.expiryKey || '';
 setState({ straddleLoading: true, straddleError: '', straddlePreview: null }, { persist: false });
 const result = await send('v17:getStraddleChain', { underlying: state.underlying, expiryKey: requestedExpiry });
 if (result?.ok) {
 setState({ straddleChain: result, straddleLoading: false, straddleSelectedSymbol: '' }, { persist: false });
 await refreshStraddleSettings();
 await Promise.all([refreshStraddleDashboard(), refreshStraddlePreview(getSelectedStraddleContract(result))]);
 } else {
 setState({ straddleLoading: false, straddleError: result?.error || 'Failed to load straddle chain' }, { persist: false });
 }
 }

 function LEGACY_RENDER_STRADDLE_MODE() {
 const sc = state.straddleChain;
 const loading = state.straddleLoading;
 const error = state.straddleError;

 // Underlying tabs
 const underlyingTabs = (api.OPTION_UNDERLYINGS || ['BTC', 'ETH']).map(u =>
 `<button type="button" class="od-ghost-btn ${u === state.underlying ? 'active' : ''}" data-options-action="set-underlying" data-underlying="${u}">${u}</button>`
 ).join('');

 // Expiry selector
 let expirySelect = '';
 if (sc?.expiries?.length) {
 expirySelect = `<select class="od-straddle-expiry-select" data-straddle-action="set-expiry">${sc.expiries.map(e =>
 `<option value="${esc(e.key)}" ${e.key === sc.expiryKey ? 'selected' : ''}>${esc(e.label)} (${days(e.daysToExpiry)})</option>`
 ).join('')}</select>`;
 }

 const header = `<div class="od-straddle-header">
 <div class="od-underlying-tabs">${underlyingTabs}</div>
 ${expirySelect}
 <button type="button" class="od-ghost-btn" data-options-action="refresh-straddle-chain">${loading ? 'Loading...' : 'Refresh'}</button>
 ${sc ? `<span class="od-straddle-spot">Spot: $${n(sc.underlyingPrice).toFixed(0)}</span><span class="od-straddle-spot">ATM: ${n(sc.atmStrike).toFixed(0)}</span>` : ''}
 </div>`;

 if (error) return `<div class="od-straddle-mode">${header}<div class="od-top-error">${esc(error)}</div></div>`;
 if (loading && !sc) return `<div class="od-straddle-mode">${header}<div class="od-loading">Loading straddle contracts...</div></div>`;
 if (!sc?.contracts?.length) return `<div class="od-straddle-mode">${header}<div class="od-empty">No native straddle (MV-) contracts found for ${esc(state.underlying)}. Click Refresh to fetch.</div></div>`;

 // Score all contracts
 const spot = n(sc.underlyingPrice);
 const scored = sc.contracts.map(c => ({
 ...c,
 score: api.scoreNativeStraddleContract?.(c, spot, 'neutral', {}, { marketContext: sc?.marketContext }) || 0,
 }));
 const best = scored.reduce((b, c) => (!b || c.score > b.score) ? c : b, null);

 // Determine the active/selected contract for the decision panel
 const selectedSym = state.straddleSelectedSymbol || (best ? best.symbol : '');
 const active = scored.find(c => c.symbol === selectedSym) || best;

 // Table
 const rows = scored.map(c => {
 const isBest = best && c.symbol === best.symbol;
 const isAtm = c.strike === sc.atmStrike;
 const isSelected = active && c.symbol === active.symbol;
 const barWidth = Math.max(0, Math.min(100, c.score));
 return `<tr class="od-straddle-row ${isAtm ? 'is-atm' : ''} ${isBest ? 'is-best' : ''} ${isSelected ? 'is-selected' : ''}" data-options-action="select-straddle-contract" data-symbol="${esc(c.symbol)}">
 <td class="od-straddle-strike">${isAtm ? '<span class="od-atm-dot"></span>' : ''}${n(c.strike).toFixed(0)}</td>
 <td>$${n(c.markPrice).toFixed(2)}</td>
 <td>$${n(c.bid).toFixed(2)}</td>
 <td>$${n(c.ask).toFixed(2)}</td>
 <td>${compact(c.volume)}</td>
 <td>${compact(c.oiContracts)}</td>
 <td>${n(c.theta).toFixed(2)}</td>
 <td>${pct(n(c.iv) * 100, 1)}</td>
 <td><div class="od-straddle-score"><div class="od-straddle-score-fill" style="width:${barWidth}%"></div></div> <span class="od-score-num">${c.score}</span></td>
 <td><button type="button" class="od-sell-icon" data-options-action="sell-native-straddle" data-symbol="${esc(c.symbol)}" data-product-id="${c.productId}" title="Sell ${esc(c.symbol)}">S</button></td>
 </tr>`;
 }).join('');

 const table = isAdvanced ? `<div class="od-straddle-table-wrap"><table class="od-straddle-table">
 <thead><tr><th>Strike</th><th>Mark</th><th>Bid</th><th>Ask</th><th>Vol</th><th>OI</th><th>Theta</th><th>IV</th><th>Score</th><th></th></tr></thead>
 <tbody>${rows}</tbody>
 </table></div>` : '';

 // ===== DECISION PANEL (below table) =====
 let decisionPanel = '';
 if (active) {
 const c = active;
 const cm = Math.max(0.000001, n(c.contractMultiplier || 1));
 const mark = n(c.markPrice);
 const strike = n(c.strike);
 const dte = n(c.daysToExpiry);
 const dteHours = Math.max(0, Math.round(dte * 24));
 const theta = n(c.theta);
 const iv = n(c.iv);
 const spread = (n(c.ask) > 0 && n(c.bid) > 0) ? n(c.ask) - n(c.bid) : 0;
 const spreadPctVal = mark > 0 ? (spread / mark * 100) : 0;

 // Short straddle P&L calculations
 const premiumPerContract = mark * cm;
 const breakevenLow = strike - mark;
 const breakevenHigh = strike + mark;
 const profitRange = breakevenHigh - breakevenLow;
 const profitRangePctVal = spot > 0 ? (profitRange / spot * 100) : 0;

 // Stop-loss from settings (default 30%)
 const slPct = 30;
 const maxLossPerContract = mark * (slPct / 100) * cm;
 const maxProfitPerContract = premiumPerContract;
 const dailyThetaPerContract = Math.abs(theta) * cm;

 // Size calculator
 const targetUSD = n(state.straddleTargetUSD || 100);
 const estQty = premiumPerContract > 0 ? Math.max(1, Math.ceil(targetUSD / premiumPerContract)) : 1;
 const totalPremium = premiumPerContract * estQty;
 const totalMaxLoss = maxLossPerContract * estQty;
 const totalDailyTheta = dailyThetaPerContract * estQty;
 const riskReward = totalMaxLoss > 0 ? (totalPremium / totalMaxLoss).toFixed(1) : 'NA';

 // Decision Tree reasoning bullets
 const reasons = [];
 if (c.score >= 85) reasons.push({ icon: '&#10003;', cls: 'profit', text: `High score (${c.score}/100) - strong candidate` });
 else if (c.score >= 65) reasons.push({ icon: '&#9679;', cls: 'info', text: `Moderate score (${c.score}/100) - acceptable` });
 else reasons.push({ icon: '&#10007;', cls: 'loss', text: `Low score (${c.score}/100) - weak candidate` });

 if (strike === sc.atmStrike) reasons.push({ icon: '&#10003;', cls: 'profit', text: 'ATM strike - maximum theta capture' });
 else reasons.push({ icon: '&#9679;', cls: 'info', text: `${Math.abs(strike - sc.atmStrike).toFixed(0)} away from ATM` });

 if (Math.abs(theta) > 300) reasons.push({ icon: '&#10003;', cls: 'profit', text: `Strong theta decay ($${dailyThetaPerContract.toFixed(2)}/day/contract)` });
 else if (Math.abs(theta) > 100) reasons.push({ icon: '&#9679;', cls: 'info', text: `Moderate theta ($${dailyThetaPerContract.toFixed(2)}/day/contract)` });
 else reasons.push({ icon: '&#10007;', cls: 'loss', text: `Weak theta ($${dailyThetaPerContract.toFixed(2)}/day/contract)` });

 if (iv > 0.30) reasons.push({ icon: '&#10003;', cls: 'profit', text: `IV ${pct(iv * 100, 1)} - elevated, premium rich` });
 else if (iv > 0.20) reasons.push({ icon: '&#9679;', cls: 'info', text: `IV ${pct(iv * 100, 1)} - moderate` });
 else reasons.push({ icon: '&#10007;', cls: 'loss', text: `IV ${pct(iv * 100, 1)} - low, thin premium` });

 if (n(c.oiContracts) > 2000) reasons.push({ icon: '&#10003;', cls: 'profit', text: `Good liquidity (OI: ${compact(c.oiContracts)}, Vol: ${compact(c.volume)})` });
 else if (n(c.oiContracts) > 500) reasons.push({ icon: '&#9679;', cls: 'info', text: `Fair liquidity (OI: ${compact(c.oiContracts)})` });
 else reasons.push({ icon: '&#10007;', cls: 'loss', text: `Low liquidity (OI: ${compact(c.oiContracts)}) - wider slippage` });

 if (spreadPctVal < 2) reasons.push({ icon: '&#10003;', cls: 'profit', text: `Tight spread (${spreadPctVal.toFixed(1)}%)` });
 else if (spreadPctVal < 5) reasons.push({ icon: '&#9679;', cls: 'info', text: `Moderate spread (${spreadPctVal.toFixed(1)}%)` });
 else reasons.push({ icon: '&#10007;', cls: 'loss', text: `Wide spread (${spreadPctVal.toFixed(1)}%) - entry cost high` });

 if (dte < 0.5) reasons.push({ icon: '&#10007;', cls: 'loss', text: `Very short DTE (${dteHours}h) - gamma risk, fast moves hurt` });
 else if (dte < 2) reasons.push({ icon: '&#9679;', cls: 'info', text: `Short DTE (${days(dte)}) - fast theta but gamma risk` });
 else reasons.push({ icon: '&#10003;', cls: 'profit', text: `DTE ${days(dte)} - good time for theta collection` });

 const reasonsHtml = reasons.map(r =>
 `<div class="od-dt-reason ${r.cls}"><span class="od-dt-icon">${r.icon}</span> ${r.text}</div>`
 ).join('');

 const verdictScore = reasons.filter(r => r.cls === 'profit').length;
 const verdictTotal = reasons.length;
 const verdictLabel = verdictScore >= 5 ? 'STRONG SELL' : verdictScore >= 3 ? 'SELL' : verdictScore >= 2 ? 'MARGINAL' : 'AVOID';
 const verdictCls = verdictScore >= 5 ? 'profit' : verdictScore >= 3 ? 'info' : verdictScore >= 2 ? 'warn' : 'loss';

 decisionPanel = `<div class="od-dt-panel">
 <div class="od-dt-header">
 <div class="od-dt-symbol">${esc(c.symbol)}</div>
 <div class="od-dt-verdict ${verdictCls}">${verdictLabel} (${verdictScore}/${verdictTotal})</div>
 </div>

 <div class="od-dt-grid">
 <div class="od-dt-section">
 <div class="od-dt-section-title">Risk / Reward</div>
 <div class="od-dt-row"><span>Profit Range</span><strong>$${breakevenLow.toFixed(0)} - $${breakevenHigh.toFixed(0)} (${profitRangePctVal.toFixed(1)}%)</strong></div>
 <div class="od-dt-row"><span>Max Profit / Ct</span><strong class="profit">$${maxProfitPerContract.toFixed(2)}</strong></div>
 <div class="od-dt-row"><span>Max Loss / Ct (${slPct}% SL)</span><strong class="loss">$${maxLossPerContract.toFixed(2)}</strong></div>
 <div class="od-dt-row"><span>R:R Ratio</span><strong>${riskReward}:1</strong></div>
 <div class="od-dt-row"><span>Breakevens</span><strong>$${breakevenLow.toFixed(0)} / $${breakevenHigh.toFixed(0)}</strong></div>
 </div>

 <div class="od-dt-section">
 <div class="od-dt-section-title">Time &amp; Greeks</div>
 <div class="od-dt-row"><span>Time to Expiry</span><strong>${days(dte)} (${dteHours}h)</strong></div>
 <div class="od-dt-row"><span>Theta / Day / Ct</span><strong class="profit">$${dailyThetaPerContract.toFixed(2)}</strong></div>
 <div class="od-dt-row"><span>IV</span><strong>${pct(iv * 100, 1)}</strong></div>
 <div class="od-dt-row"><span>Delta</span><strong>${n(c.delta).toFixed(3)}</strong></div>
 <div class="od-dt-row"><span>Gamma</span><strong>${n(c.gamma).toFixed(5)}</strong></div>
 <div class="od-dt-row"><span>Contract Multiplier</span><strong>${cm}</strong></div>
 </div>
 </div>

 <div class="od-dt-section">
 <div class="od-dt-section-title">Decision Tree</div>
 ${reasonsHtml}
 </div>

 <div class="od-dt-order-section">
 <div class="od-dt-section-title">Size Calculator &amp; Order</div>
 <div class="od-dt-size-row">
 <label>Target Profit ($)</label>
 <input type="number" class="od-dt-input" id="odStraddleTarget" value="${n(state.straddleTargetUSD)}" min="1" max="1000000" step="10" data-straddle-action="set-target"/>
 <span class="od-dt-arrow">&#8594;</span>
 <div class="od-dt-calc">
 <div class="od-dt-calc-item"><span>Est. Qty</span><strong>${estQty}</strong></div>
 <div class="od-dt-calc-item"><span>Total Premium</span><strong class="profit">$${totalPremium.toFixed(2)}</strong></div>
 <div class="od-dt-calc-item"><span>Max Loss (${slPct}% SL)</span><strong class="loss">$${totalMaxLoss.toFixed(2)}</strong></div>
 <div class="od-dt-calc-item"><span>Daily &theta;</span><strong class="profit">$${totalDailyTheta.toFixed(2)}/d</strong></div>
 </div>
 </div>
 <div class="od-dt-order-bar">
 <div class="od-dt-order-summary">
 <strong>SELL ${estQty}x ${esc(c.symbol)}</strong>
 <span>@ $${mark.toFixed(2)} | SL: $${(mark * (1 + slPct / 100)).toFixed(2)} | TP: $0.00</span>
 </div>
 <button type="button" class="od-straddle-sell-btn ${state.placing ? 'disabled' : ''}" data-options-action="place-straddle-order" data-symbol="${esc(c.symbol)}" data-product-id="${c.productId}" data-qty="${estQty}" data-mark="${mark}" data-strike="${c.strike}" data-expiry-ts="${c.expiryTs}" data-expiry-key="${c.expiryKey || ''}" data-cm="${cm}" data-score="${c.score}" data-underlying="${c.underlying || state.underlying}" data-spot="${spot}" data-sl-pct="${slPct}">${state.placing ? 'Placing...' : `Sell ${estQty} Straddle${estQty > 1 ? 's' : ''}`}</button>
 </div>
 </div>
 </div>`;
 }

 return `<div class="od-straddle-mode">${header}${table}${decisionPanel}</div>`;
 }

