 const score = n(preview?.score || active.score);
 const softGate = n(preview?.softGateThreshold || settings.minTradeQuality || 70);
 const canPlace = preview?.canPlace !== false;
 const warningRequired = !!preview?.warningRequired;
 const tone = !canPlace ? 'loss' : warningRequired ? 'warn' : score >= 85 ? 'profit' : score >= 70 ? 'info' : 'warn';
 const settingsCopy = `Mode ${esc(preview?.entryMode || settings.entryMode || 'limit')} | Stop ${n(preview?.stopLossPct || settings.legStopLossPct || 30).toFixed(0)}% | Close ${n(settings.closeMinutesBeforeExpiry || 30)}m pre-expiry${settings.profileId ? ` | Profile ${esc(settings.profileId)}` : ''}`;
 const reasons = [
 score >= 85
 ? { icon: '&#10003;', cls: 'profit', text: `Score ${score}/100 - premium and liquidity are aligned` }
 : score >= softGate
 ? { icon: '&#9679;', cls: 'info', text: `Score ${score}/100 - above the advisory gate ${softGate}` }
 : { icon: '&#9888;', cls: 'warn', text: `Score ${score}/100 - below the advisory gate ${softGate}` },
 n(active.strike) === n(sc.atmStrike)
 ? { icon: '&#10003;', cls: 'profit', text: 'ATM strike selected for maximum theta capture' }
 : { icon: '&#9679;', cls: 'info', text: `${Math.abs(n(active.strike) - n(sc.atmStrike)).toFixed(0)} away from ATM strike` },
 n(active.spreadPct) <= 2
 ? { icon: '&#10003;', cls: 'profit', text: `Tight spread ${pct(n(active.spreadPct), 1)}` }
 : { icon: '&#9888;', cls: 'warn', text: `Spread ${pct(n(active.spreadPct), 1)} needs caution` },
 n(active.oiContracts) >= 1000
 ? { icon: '&#10003;', cls: 'profit', text: `Liquidity OI ${compact(active.oiContracts)} | Vol ${compact(active.volume)}` }
 : { icon: '&#9888;', cls: 'warn', text: `Thin liquidity OI ${compact(active.oiContracts)} | Vol ${compact(active.volume)}` },
 dte < 1
 ? { icon: '&#9888;', cls: 'warn', text: `Short DTE ${days(dte)} means faster gamma and tighter management` }
 : { icon: '&#10003;', cls: 'profit', text: `DTE ${days(dte)} keeps theta attractive without same-hour pressure` },
 ];
 if (!canPlace && preview?.reason) reasons.push({ icon: '&#10007;', cls: 'loss', text: preview.reason });
