 function normalCdf(value) {
 const x = n(value);
 const sign = x < 0 ? -1 : 1;
 const z = Math.abs(x) / Math.sqrt(2);
 const t = 1 / (1 + 0.3275911 * z);
 const erf = 1 - (((((1.061405429 * t - 1.453152027) * t) + 1.421413741) * t - 0.284496736) * t + 0.254829592) * t * Math.exp(-z * z);
 return 0.5 * (1 + sign * erf);
 }

 function buildStraddleProbabilityModel(preview, contract, spot) {
 const strike = n(contract?.strike || preview?.strike || spot, spot);
 const dte = Math.max(0.02, n(contract?.daysToExpiry || preview?.daysToExpiry || 1, 1));
 const iv = Math.max(0.05, n(contract?.iv || preview?.iv || 0.45, 0.45));
 const expected = Math.max(1, n(preview?.expectedMoveWidth, spot * iv * Math.sqrt(dte / 365)));
 const low = n(preview?.breakEvenLow, strike - expected);
 const high = n(preview?.breakEvenHigh, strike + expected);
 const sigma = Math.max(1, expected / 1.25);
 const probRange = Math.max(0, Math.min(100, (normalCdf((high - spot) / sigma) - normalCdf((low - spot) / sigma)) * 100));
 const bandPct = spot > 0 ? ((high - low) / spot) * 100 : 0;
 const moveLowPct = spot > 0 ? Math.abs(spot - low) / spot * 100 : 0;
 const moveHighPct = spot > 0 ? Math.abs(high - spot) / spot * 100 : 0;
 const minMovePct = Math.min(moveLowPct || 0, moveHighPct || 0);
 const gammaRisk = Math.min(100, Math.max(0, (1 / Math.max(0.15, dte)) * 16 + Math.max(0, 18 - minMovePct) * 2));
 return {
 low,
 high,
 expected,
 probRange,
 bandPct,
 minMovePct,
 gammaRisk,
 expiryLabel: dte < 1 ? 'Same-day gamma' : dte <= 3 ? 'Near expiry' : 'Standard expiry',
 };
 }

